func check(name, content string, attempts, goroutines int) error {
    src := pagemeta.Source{Value: content}
    open := src.ValueAsOpenReadSeekCloser()

    for attempt := 0; attempt < attempts; attempt++ {
        var wg sync.WaitGroup
        start := make(chan struct{})
        errs := make(chan string, goroutines)
